"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[1477],{10:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/Fundamental of graphics/Rendering","metadata":{"permalink":"/blog/Fundamental of graphics/Rendering","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/Fundamental of graphics/Rendering.md","source":"@site/blog/Fundamental of graphics/Rendering.md","title":"\u6e32\u67d3\uff08\u864e\u4e66\uff09","description":"\u4ee3\u7801\u5b9e\u73b0\u8fc7\u7a0b\u8bb0\u5f55","date":"2023-03-03T15:25:44.000Z","formattedDate":"March 3, 2023","tags":[{"label":"CG","permalink":"/blog/tags/cg"}],"readingTime":9.76,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"\u6e32\u67d3\uff08\u864e\u4e66\uff09","tags":["CG"]},"nextItem":{"title":"c++\u9762\u5411\u5bf9\u8c61","permalink":"/blog/c++\u9762\u5411\u5bf9\u8c61/\u9762\u5411\u5bf9\u8c61"}},"content":"\x3c!--truncate--\x3e\\n\\n## \u4ee3\u7801\u5b9e\u73b0\u8fc7\u7a0b\u8bb0\u5f55\\n\\n\u5177\u4f53\u4ee3\u7801\u89c1https://github.com/CanoeByGuitar/chenhui-lib\\n\\n### \u5149\u7ebf\u548c\u5404\u79cd\u7269\u4f53\u6c42\u4ea4\\n\\n![image-20230311143332619](assets/image-20230311143332619.png)\\n\\n![image-20230311143310242](assets/image-20230311143310242.png\\n\\n![image-20230311143322657](assets/image-20230311143322657.png)\\n\\n![image-20230311143345703](assets/image-20230311143345703.png)\\n\\n> \u4e0a\u9762\u90a3\u4e2a\u628a\u6cd5\u7ebf\u4ece[-1,1]\u6620\u5c04\u5230[0,255,255]\\n\\n\u5e26\u6709Anti-aliasing\u7684\u591a\u7269\u4f53\u6c42\u4ea4\\n\\n![image-20230311143820082](assets/image-20230311143820082.png)\\n\\n![image-20230311143840947](assets/image-20230311143840947.png)\\n\\n### Lambertian Shading\\n\\n```cpp\\n// light\\nvec3 light_pos(0,4,-2);\\n    float intensity = 1.f;\\n    Light light(light_pos, intensity);\\n```\\n\\n```cpp\\n// World\\n    Material *m = new Material(vec3(100, 100, 100));\\n    SurfaceList world(nullptr);\\n    world.add(std::make_shared<Circle>(Circle(m, vec3(0, 0, -1), 0.5)));\\n    world.add(std::make_shared<Circle>(Circle(m, vec3(0, -100.5, -1), 100)));\\n```\\n\\n\\n\\n```cpp\\nvec3 ray_color(SurfaceList &world, Ray r, Light light){\\n    Intersection inter1;\\n    vec3 color(0, 0, 0);\\n    if(world.getIntersect(r, 0.f, INF, inter1)){\\n        auto p = inter1.point;\\n        auto n = inter1.normal;\\n        auto light_ray = Ray(p, light.pos - p);\\n        auto l = light_ray.direction();\\n        auto k_d = inter1.m->k_d;\\n        Intersection inter2;\\n        if(world.getIntersect(light_ray, 0.f, INF, inter2)){\\n            // light cannot arrive at obj\\n        }else{\\n            auto I = light.intensity;\\n            color += k_d * max(n * l, 0.f) * I;\\n        }\\n    }\\n    return color;\\n}\\n```\\n\\n\\n\\n![image-20230311142508493](assets/image-20230311142508493.png)\\n\\n\\n\\n\u68c0\u67e5\u4ee3\u7801 \u6750\u8d28\u91cc\u7684k_d\u5e94\u8be5\u662f[0,1]\u533a\u95f4\u800c\u4e0d\u662f[0,255]\\n\\n```cpp\\nMaterial *m = new Material(vec3(0.7f, 0.7f, 0.7f));\\n```\\n\\n![image-20230311143039992](assets/image-20230311143039992.png)\\n\\n\\n\\n### Blinn-Phong Shading\\n\\n\u7ed9\u8f93\u51facolor\u52a0\u4e86\u4e00\u4e2aclamp\uff0c\u8d85\u8fc71\u7684\u8f93\u51fa1\uff0c\u5426\u5219ppm\u4f1a\u88ab\u5927\u4e8e255\u7684\u6570\u89e3\u6790\u6210\u9ed1\u7684\\n\\n![image-20230311145558608](assets/image-20230311145558608.png)\\n\\n\\n\\n\u4e0b\u56fe\u7684\u53c2\u6570\u4e3a\uff1a\\n\\n```cpp\\n// World\\n    auto *m1 = new Material(vec3(1, 0, 0), vec3(1, 0, 0), vec3(1, 0, 0));\\n    auto *m2 = new Material(vec3(0, 1, 0), vec3(0, 1, 0), vec3(0, 1, 0));\\n    auto *m3 = new Material(vec3(0.25, 0.25, 0.25), vec3(0.25, 0.25, 0.25), vec3(0.25, 0.25, 0.25));\\n    SurfaceList world(nullptr);\\n    world.add(std::make_shared<Circle>(Circle(m1, vec3(0.42, -0.08, -1.5), 0.4)));\\n    world.add(std::make_shared<Circle>(Circle(m2, vec3(-0.35, -0.1, -1.3), 0.35)));\\n    world.add(std::make_shared<Circle>(Circle(m3, vec3(0, -100.5, -1), 100)));\\n\\n    // light\\n    std::vector<Light> light_list;\\n    light_list.emplace_back(vec3(-4, 4, -3), 0.2f);\\n    light_list.emplace_back(vec3(4, 4, -3), 0.5f);\\n    light_list.emplace_back(vec3(0, 6, 0), 0.3f);\\n```\\n\\n```cpp\\nvec3 ray_color(SurfaceList &world, Ray r, const std::vector<Light> &light_list) {\\n    Intersection inter1;\\n    vec3 color(0, 0, 0);\\n    if (world.getIntersect(r, 0.f, INF, inter1)) {\\n        auto p = inter1.point;\\n        auto n = inter1.normal;\\n        auto v = -r.direction();\\n        auto k_d = inter1.m->k_d;\\n        auto k_s = inter1.m->k_s;\\n        auto k_a = inter1.m->k_a;\\n        // ambient shading\\n        float I_a = 0.2;\\n        color += k_a * I_a;\\n        for (auto light: light_list) {\\n            auto light_ray = Ray(p, light.pos - p);\\n            auto l = light_ray.direction();\\n            auto h = unit_vec((v + l));\\n            Intersection inter2;\\n            if (world.getIntersect(light_ray, 0.f, INF, inter2)) {\\n                // light cannot arrive at obj\\n            } else {\\n                auto I = light.intensity;\\n                color += k_d * max(n * l, 0.f) * I + k_s * I * pow(max(0.f, n * h), 10);\\n            }\\n        }\\n    }else{\\n        // background color\\n        return vec3(0.847, 0.914, 0.996);\\n    }\\n    return clamp(color, 0, 1);\\n}\\n```\\n\\n\u8c03\u6574\u4e0b\u9762\u7684p\u5f97\u5230\u4e0d\u540c\u7684\u6750\u8d28\\n\\n```L = k_d* I * max(0,n.dot(l))+ k_s* I  * max(0,n.dot(h))^p // p\u662f\u4e3a\u4e86\u52a0\u901f\u4ece\u9ad8\u5149\u5230\u6d88\u5931\u7684\u53d8\u5316\u6548\u679c\u7684```\\n\\n![image-20230311162947638](assets/image-20230311162947638.png)\\n\\n![image-20230311164147390](assets/image-20230311164147390.png)\\n\\n## Math\\n\\n### \u70b9\u5230\u76f4\u7ebf\u8ddd\u79bb\\n\\n![image-20230222153001768](assets/image-20230222153001768.png)\\n\\n\\n\\n### \u8ba1\u7b97\u884c\u5217\u5f0f\\n\\nLU\u5206\u89e3 L\u4e0b\u4e09\u89d2 U\u4e0a\u4e09\u89d2\\n\\n### \u53d8\u6362\u77e9\u9635\\n\\n\u9996\u5148\u6ce8\u610f\uff0c**\u6b63\u4ea4\u77e9\u9635\u5305\u62ec\u65cb\u8f6c\u548c\u955c\u9762\u53cd\u5c04\u4e24\u79cd\u60c5\u51b5**\\n\\n$A=A^{T}$ \\n\\ndet(A) == 1 ==> rotation \\n\\ndet(A) == -1 ==> reflection\\n\\n\u4efb\u610f\u4e00\u4e2a\u5bf9\u6210\u77e9\u9635A\uff0c\u90fd\u8868\u793a\u6cbf\u7740\u67d0\u4e00\u4e2a\u65b9\u5411\uff08x\'oy\')\u8fdb\u884c\u653e\u7f29\uff0cx\'oy\'\u7531\u7279\u5f81\u5411\u91cf\u7ec4\u6210\\n\\n==symmetric matrices can be decomposed via eigenvalue diagonalization into a rotation times a scale times the inverse-rotation==\\n\\n![image-20230225021423520](assets/image-20230225021423520.png)\\n\\n\u76f8\u4f3c\u5bf9\u89d2\u5316$ A =   R  S R^{T} $\\n\\n\u65cb\u8f6c ==> \u653e\u7f29 ==> \u8f6c\u56de\u6765\\n\\n\\n\\n3D \u65cb\u8f6c\u77e9\u9635\\n\\n![image-20230225221351128](assets/image-20230225221351128.png)\\n\\n### SVD\\n\\nsingular value decomposition\\n\\n==every matrix can be decomposed via SVD into a rotation times a scale times another rotation==\\n\\n![image-20230225021509148](assets/image-20230225021509148.png)\\n\\n\\n\\n>  \u5982\u4f55\u89e3\u51b3\u6b63\u4ea4\u77e9\u9635\u4e0d\u4e00\u5b9a\u662f\u65cb\u8f6c\u77e9\u9635\u7684\u95ee\u9898\uff1f(Dynamic Deformables P181)\\n\\n**\u624b\u7b97SVD\u5206\u89e3\uff1a**\\n\\n$A = UBV^T ==> AA^T = UB^TBU^T$\\n\\n$A = UBV^T ==> A^TA = VB^TBV^T$\\n\\n\u5bf9\u79f0\u77e9\u9635\u6b63\u4ea4\u76f8\u4f3c\u5316\uff0c\u6c42\u7279\u5f81\u503c\u3001\u7279\u5f81\u5411\u91cf, \u7279\u5f81\u503c\u5f00\u6839\u5c31\u662fB\uff0c\u539f\u5219\u4e0a\u7edf\u4e00\u53d6B\u4e3a\u6b63\u7684\u3002\\n\\n**\u6781\u5206\u89e3**\uff1a\\n\\n\u4efb\u610f\u4e00\u4e2a\u77e9\u9635A\u53ef\u4ee5\u5206\u89e3\u4e3a $A = R S$\\n\\n\u5176\u4e2dR\u662f \u6b63\u4ea4\u77e9\u9635\uff0c S\u662f\u5bf9\u79f0\u534a\u6b63\u5b9a\u77e9\u9635\\n\\n\u5206\u89e3\u8fc7\u7a0b\u501f\u52a9\u4e8eSVD\\n\\n$A=UBV^T = (UV^T) (VBV^T)$\\n\\n\u4ee4$R = UV^T$, $S = VBV^T$ \\n\\n\u56e0\u4e3aU V\u4e3a\u6b63\u4ea4\u77e9\u9635\uff0c\u6240\u4ee5$UV^T$\u4e5f\u662f\u6b63\u4ea4\u77e9\u9635\uff08\u4e58\u81ea\u5df1\u8f6c\u7f6e\u4e3aE\uff09\\n\\nB\u662f\u5bf9\u89d2\u9635\uff0c\u4e14\u6b63\u5b9a\uff0c\u6240\u4ee5S\u5bf9\u79f0\u6b63\u5b9a\u3002\\n\\n**\u5b9e\u73b0**\uff08JacobiSVD\uff09\\n\\n> https://zhuanlan.zhihu.com/p/459369233\\n>\\n> Matrix Computation(2013) p447\\n\\n* \u5148\u7b97\u6781\u5206\u89e3\uff0c $A = R S$\uff0c\u5f97\u5230\u5bf9\u79f0\u77e9\u9635S\\n* \u5bf9S\u8fdb\u884c**Jacobi\uff08Givens\uff09\u65cb\u8f6c\u5bf9\u89d2\u5316**\uff0c\u53bb\u6389\u975e\u4e3b\u5bf9\u89d2\u7684\u975e\u96f6\u5143\u7d20\\n\\n$\\\\frac{\\\\partial f(z)}{\\\\partial \\\\Im z}=i \\\\frac{\\\\partial f(z)}{\\\\partial \\\\Re z}$\\n\\n### \u9f50\u6b21\u5750\u6807\uff08*homogeneous coordinates*\uff09\\n\\n\u70b9 ==> (x, y, 1)\\n\\n\u65b9\u5411 ==> (x, y, 0)\\n\\n## Ray tracing\\n\\n```cpp\\nfor each pixel do\\n  compute view ray\\n  find first hit object and its norml n\\n  set pixel color from hit point, light, normal n\\n```\\n\\n\\n\\n### Gen rays\\n\\n![image-20230220215106252](assets/image-20230220215106252.png)\\n\\n\\n\\n$p(t)=e+(s-e)t$\\n\\n![image-20230220215229532](assets/image-20230220215229532.png)\\n\\n![image-20230220215237979](assets/image-20230220215237979.png)\\n\\n\u76f8\u673a\u7684view port\u662fw\u7684\u53cd\u65b9\u5411\uff08Opengl\u91cc\u4e5f\u662f\u5982\u6b64\uff09\u3002\\n\\n![image-20230220221002172](assets/image-20230220221002172.png)\\n\\n#### Orthographic view\\n\\n```cpp\\n// input [l,r,b,t, nx, ny, u, v, w]\\n// pixel (i,j)  ==> position coordinates\\npx = l + (r - l) / nx * (i + 0.5)\\npy = b + (t - b) / ny * (j + 0.5)\\n\\nray.direction = -w\\nray.origin = e + px * u + py * v\\n```\\n\\n\\n\\n#### Perspective Views\\n\\n```cpp\\npx = l + (r - l) / nx * (i + 0.5)\\npy = b + (t - b) / ny * (j + 0.5)\\n\\nray.direction = -d * w + px * u + py * v;\\nray.origin = e;\\n```\\n\\n### Ray-Object intersection\\n\\n##### Ray-Sphere\\n\\n![image-20230221213907621](assets/image-20230221213907621.png)\\n\\n![image-20230221213919969](assets/image-20230221213919969.png)\\n\\n##### Ray-Triangle\\n\\n![image-20230221215048656](assets/image-20230221215048656.png)\\n\\n![image-20230221215210083](assets/image-20230221215210083.png)\\n\\n```cpp\\n// ray-triangle intersection\\ncompute t\\nif(t < t0 || t > t1) return false;\\ncompute gamma;\\nif(gamma < 0 || gamma > 1) return false;\\ncompute beta;\\nif(beta < 0 || beta > 1 - gamma) return false;\\nreturn true;\\n```\\n\\n##### Ray-Polygon\\n\\n![image-20230221221501295](assets/image-20230221221501295.png)\\n\\n![image-20230307233719862](assets/image-20230307233719862.png)\\n\\n2D\u5224\u65adp\u5728\u591a\u8fb9\u5f62\u5185/\u5916\\n\\n```cpp\\nray from p intersects with polygon boundary\\ncount the hit number h\\nif(h is odd) return inside\\nelse return outside\\n```\\n\\n\\n\\n![image-20230221221516596](assets/image-20230221221516596.png)\\n\\n##### A group of Objects\\n\\n```cpp\\n// input [t0, t1] ray\\nintersection{\\n  bool hit = false\\n  for(each object o: group){\\n    if(o intersets ray in t && t >= t0 && t < t1){\\n      hit = true;\\n      hit_obj = o;\\n      t1 = t;\\n    }\\n  }\\n  return hit\\n}\\n\\n```\\n\\n\\n\\n\\n\\n### Shading\\n\\nimportant variables: \\n\\n* light direction **l**\\n\\n* view dirction **v**\\n* ![image-20230222221603312](assets/image-20230222221603312.png)\\n\\n#### Lambertian Shading\\n\\n\u843d\u5728surface\u4e0a\u7684\u5149\u7684\u91cf\u53ea\u548c\u5165\u5c04\u89d2\u5ea6\u76f8\u5173\uff08view independent \u4e0d\u8003\u8651\u4eba\u773c\u4f4d\u7f6e\u770b\u5230\u7684\u5149\u7684\u4e0d\u540c\uff09\\n\\n* \u5782\u76f4\u7684\u65f6\u5019 \u5149\u6700\u591a\\n\\n* \u76f8\u5207\u7684\u65f6\u5019 \u5149\u4e3a0\\n\\n* \u4e24\u8005\u4e4b\u95f4\u65f6\uff0c\u548c\u5165\u5c04\u5149\u4e0eface normal\u7684\u5939\u89d2theta\u6210\u6b63\u6bd4\u3002\\n\\n  ```cpp\\n  L = k_d * I * max(0, n.dot(l)); \\n  \\n  // k_d: diffuse coef / surface color    3 channels\\n  // I: light intensity     3 channels\\n  // n: unit face normal\\n  // l: unit light dir\\n  ```\\n\\n  \\n\\n#### Blinn-Phong Shading\\n\\n\u5728Lambertian\u7684\u57fa\u7840\u4e0a\u989d\u5916\u8003\u8651\u9ad8\u5149\uff08Phong\u548cBlinn\u4e24\u4e2a\u4eba\u5206\u522b\u5b8c\u6210\u548c\u6539\u8fdb\uff09\\n\\n![image-20230223012824894](assets/image-20230223012824894.png)\\n\\n```cpp\\nh = (v + l).norm()\\n  // Labert diffusion  + specular\\nL = k_d* I * max(0,n.dot(l))+ k_s* I  * max(0,n.dot(h))^p // p\u662f\u4e3a\u4e86\u52a0\u901f\u4ece\u9ad8\u5149\u5230\u6d88\u5931\u7684\u53d8\u5316\u6548\u679c\u7684\\n```\\n\\n#### Ambient Shading\\n\\n\u7136\u800c\u5728\u65e9\u671f\u7684blinn-phong\u6a21\u578b\u4e0b\uff0c\u6ca1\u6709\u88ab\u5149\u6e90\u76f4\u63a5\u7167\u5c04\u7684\u5730\u65b9\u5c31\u662f\u7eaf\u9ed1\u7684\uff0c\u56e0\u4e3ablinn-phong\u4e0d\u8003\u8651\u95f4\u63a5\u5149\uff0c\u6240\u4ee5\u4e00\u4e2a\u8ba8\u5de7\u7684\u65b9\u6cd5\u662f\uff0c\\n\\n\u7ed9surface\u8868\u9762\u9ed8\u8ba4\u9644\u4e0a\u4e00\u4e2a\u989c\u8272\uff0c\u53ebambient shading\\n\\n\u4ee5\u4e0a\u4e09\u5757\u6574\u4f53\u6784\u6210blinn-phong\u6a21\u578b\\n\\n```cpp\\nL = diffusion + specular + ambient(\u73af\u5883\u5149)\\nL = k_d* I * max(0,n.dot(l))+ k_s* I  * max(0,n.dot(h))^p + k_a * I_a // \u53ef\u4ee5\u6240\u6709\u7684surface k_a\u90fd\u76f8\u540c\uff0c\u4e5f\u53ef\u4ee5\u4e0d\u4e00\u6837\\n```\\n\\n![image-20230311145636904](assets/image-20230311145636904.png)\\n\\n#### Multiple Point Lights\\n\\n![image-20230223013800906](assets/image-20230223013800906.png)\\n\\n> \u7591\u95ee\uff1a$I$\u600e\u4e48\u8bbe\u5b9a, \u4e0d\u4f1a\u4ea7\u751f\u8fc7\u7206\u5417\uff1f\\n\\n\\n\\n### A ray tracing program\\n\\n```cpp\\nfor each pixel{\\n  compute viewing ray r\\n  if(r hits a object with t in [0, +inf]){\\n    compute normal n;\\n    evaluating shading and set color to the pixel\\n  }else{\\n    set pixel to background color\\n  }\\n}\\n```\\n\\nOOP\u7c7b\u8bbe\u8ba1\\n\\n```cpp\\nclass surface: geometry{\\n  virtual bool hit(ray r+td, real t0, real t1, hit_record rec);\\n  virtual box bounding_box()\\n    \\n  private material *mtl;\\n}\\n\\nclass sphere:surface{\\n  box bounding_box(){\\n    vec3 min = center - vec3(radius, radius, radius);\\n    vec3 max = center + vec3(radius, radius, radius);\\n    return box(min, max);\\n  }\\n}\\n```\\n\\n### Shadows\\n\\n![image-20230223191948973](assets/image-20230223191948973.png)\\n\\nshadow ray\uff08\u533a\u5206\u4e0eview ray\uff09 \u7528\u6765\u5224\u65ad\u662f\u5426\u5728\u9634\u5f71\u4e2d\uff08\u5982\u679chit\u4e86object\uff0c\u5219\u5728\u9634\u5f71\u4e2d\uff09\\n\\n```cpp\\np+t*l, t in [0,+inf)\\n             \\n// \u5b9e\u8df5\u4e2d\u901a\u5e38\u4e3a\\nt in [kesi, +inf] // \u9632\u6b62\u6570\u503c\u8bef\u5dee\u5bfc\u81f4intersect with p\u672c\u8eab\u5728\u7684\u5e73\u9762\u3002\\n```\\n\\n![image-20230223205039759](assets/image-20230223205039759.png)\\n\\n\u81f3\u6b64\uff0c\u66f4\u65b0ray tracing\u4e2d\u8ba1\u7b97\u67d0\u4e2a\u50cf\u7d20\u989c\u8272\u7684\u7b97\u6cd5\\n\\n```cpp\\nraycolor(e+t*d, t0, t1){\\n  if(hit(e + t*d, t0, t1, &rec)){\\n    p = e + (hit_record).t * d;\\n    color c = rec.k_a * I_a; // ambient light\\n    \\n    // \u5224\u65ad\u80fd\u5426\u88ab\u5149\u6e90\u7167\u5230\\n    if(not hit(p + s*l, kesi,inf, &second_record)){\\n      // \u6ca1\u6709\u9634\u5f71\\n      vec3 h = (l.norm() + (-d).norm()).norm();\\n      c = c + rec.k_d*I*max(0, n*l) + rec.k_s * I * (n  * h)^(rec.p);\\n    }else{\\n      // \u6709\u9634\u5f71\u4e0d\u505a\u5176\u4ed6\u5904\u7406\\n    }\\n  }else{\\n    // \u6ca1\u6709\u770b\u5230\u7269\u4f53\\n    return background;\\n  }\\n}\\n```\\n\\n## Viewing\\n\\nObject Space   ==>  World Space ==> Camera Space ==> Canonical View Volume$[-1,-1]^2$ ==> Screen Space\\n\\n  \\t\\t\\t\\t\\t\\tM\\t\\t\\t\\t\\t\\t\\t V\\t\\t\\t\\t\\t\\t\\t\\tP\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\tviewport transformation\\n\\n\\n\\n\u4e00\u4e9b\u522b\u79f0\uff1a\\n\\nCanonical View Volume\uff1a **Clip Space**\uff0c Normalized device coordinates\uff08**NDC**\uff09\\n\\n\\n\\n\\n\\n![image-20230309004657706](assets/image-20230309004657706.png)\\n\\n\\n\\n\\n\\n### Viewport Transformation\\n\\n$[-1,1]^2 ==> [-0.5, nx-0.5] \\\\times [-0.5,ny-0.5]$\\n\\n![image-20230309010736288](assets/image-20230309010736288.png)\\n\\n\u52a0\u4e0az\u8f74\uff0c\u8ba9z\u4fdd\u6301\u4e0d\u53d8\\n\\n![image-20230309010805176](assets/image-20230309010805176.png)\\n\\n### Projection transformation\\n\\n#### Orthographic\\n\\n $[l, r] \xd7 [b, t] \xd7 [f, n] ==> [-1,1]^3$\\n\\n\u524d\u8005\u53d6\u51b3\u4e8e\u7528\u6237\u8bbe\u5b9a\\n\\n![image-20230309013611534](assets/image-20230309013611534.png)\\n\\ne.g:\\n\\nn = -0.01\\n\\nf = -150\\n\\n![image-20230309013717698](assets/image-20230309013717698.png)\\n\\n#### Projective\\n\\n\\n\\n\\n\\n### View\uff08Camera\uff09 transformation\\n\\n**world space[x,y,z]  ===> camera space[u, v, w]**\\n\\n[u, v, w] can be generated from camera info\uff1a\\n\\n* eye position: **e**\\n* gaze direction: **g**\\n* view-up vector: **t** \u53ea\u662f\u628a\u89c2\u5bdf\u8005\u7684\u5934\u90e8\u5206\u6210\u5de6\u53f3\u4e24\u4e2a\u90e8\u5206\\n\\n![image-20230310003101303](assets/image-20230310003101303.png)\\n\\n\\n\\n![image-20230310005027077](assets/image-20230310005027077.png)\\n\\n![image-20230310005147083](assets/image-20230310005147083.png)\\n\\n\u53ef\u4ee5\u7406\u89e3\u6210\u5148\u79fb\u52a8-e\u5230\u539f\u70b9\u518d\u65cb\u8f6c\\n\\n$M = M_{vp}M_{orth}M_{cam}$"},{"id":"/c++\u9762\u5411\u5bf9\u8c61/\u9762\u5411\u5bf9\u8c61","metadata":{"permalink":"/blog/c++\u9762\u5411\u5bf9\u8c61/\u9762\u5411\u5bf9\u8c61","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/c++\u9762\u5411\u5bf9\u8c61/\u9762\u5411\u5bf9\u8c61.md","source":"@site/blog/c++\u9762\u5411\u5bf9\u8c61/\u9762\u5411\u5bf9\u8c61.md","title":"c++\u9762\u5411\u5bf9\u8c61","description":"\u5934\u6587\u4ef6\u603b\u4f53\u5e03\u5c40","date":"2023-02-15T12:12:11.000Z","formattedDate":"February 15, 2023","tags":[{"label":"c++","permalink":"/blog/tags/c"}],"readingTime":17.17,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"c++\u9762\u5411\u5bf9\u8c61","tags":["c++"]},"prevItem":{"title":"\u6e32\u67d3\uff08\u864e\u4e66\uff09","permalink":"/blog/Fundamental of graphics/Rendering"},"nextItem":{"title":"\u7ea2\u9ed1\u6811","permalink":"/blog/RBTree/\u7ea2\u9ed1\u6811"}},"content":"\x3c!--truncate--\x3e\\n\\n## \u5934\u6587\u4ef6\u603b\u4f53\u5e03\u5c40\\n\\n![image-20230215212402568](assets/image-20230215212402568.png)\\n\\nguard\uff08\u9632\u536b\u5f0f\u58f0\u660e\uff09\\n\\n\u53ea\u6709\u7b2c\u4e00\u6b21include\u4f1ainclude\u8fdb\u6765\uff0c\u7b2c\u4e8c\u6b21\u4e0d\u4f1a\u88abinclude\u8fdb\u6765\\n\\n```\\n#ifndef __Complex__\\n#define __Complex__\\n...\\n\\n\\n#endif\\n```\\n\\n\u5b9a\u4e49\u4e00\u4e2a\u590d\u6570\\n\\n```cpp\\nclass complex{\\n  public:\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\\n   ...\\n  private:\\n  double re,im;\\n}\\n\\ncomplex c1(0,0.5)\\n```\\n\\n\u7f3a\u70b9\uff1a\u5982\u679c\u60f3\u628adouble\u6539\u4e3afloat\u5c31\u5f97\u91cd\u65b0\u5b9a\u4e49\u4e00\u4e2a\u7c7b\\n\\n===> template(\u6a21\u7248)\\n\\n```cpp\\ntemplate<typename T>\\nclass complex{\\n  public:\\n  complex(T r = 0,T i = 0): re(r)\\t,im(i){}\\n   ...\\n  private:\\n  T re,im;\\n}\\n\\ncomplex<double> c1(0,0.5)\\ncomplex<float> c1(0,0.5)\\n```\\n\\n\\n\\n**Inline(\u5185\u8054)**\\n\\n\u7a0b\u5e8f\u5458\u8bbe\u8ba1\u662f\u5426inline\u53ea\u662f\u7ed9\u7f16\u8bd1\u5668\u5efa\u8bae\uff0c\u7f16\u8bd1\u5668\u6700\u7ec8\u662f\u5426inline\u53d6\u51b3\u4e8e\u51fd\u6570\u662f\u5426\u590d\u6742\u3002\\n\\n```cpp\\nclass complex{\\n  public:\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\\n  \\n  // \u5728class\u672c\u4f53\u91cc\u76f4\u63a5\u5b9a\u4e49\u7684\u51fd\u6570\u4f1a\u81ea\u52a8inline\\n  double real() const\\t{return re;} // inline function\\n  double img() const;// declaration\\n  private:\\n  double re,im;\\n}\\n\\n// class\u672c\u4f53\u5185\u58f0\u660e\u4e86\u7684\uff0c\u800c\u672c\u4f53\u5916\u60f3\u8981\u5efa\u8bae\u7f16\u8bd1\u5668inline\u9700\u8981\u52a0inline\u5173\u952e\u8bcd\\ninline double img(const complex& x){\\n  return x.img();\\n}\\n\\nvoid real(double r){real = r;}\\n```\\n\\n\\n\\n**\u6784\u9020\u51fd\u6570**\\n\\n```cpp\\nclass complex{\\n  public:\\n  // \uff081\uff09\u6700\u597d\u5199\u6210\u8fd9\u6837\uff0c\u76f4\u63a5\u521d\u59cb\u5316 r\u548ci\\n  complex(double r = 0,double i = 0): // =0\u4e3a\u9ed8\u8ba4\u53c2\u6570\\n  re(r)\\t,im(i) // \u521d\u59cb\u5217\\n  {}   // \u8d4b\u503c\\n  // \uff082\uff09\u800c\u6700\u597d\u4e0d\u8981\u5199\u6210\u8fd9\u6837\uff0c\u5148\u521d\u59cb\u5316\uff0c \u518d\u8d4b\u503cr\u548ci\\n  complex(double r = 0,double i = 0) {re = r; im = i};\\n  \\n  // \u5728class\u672c\u4f53\u91cc\u76f4\u63a5\u5b9a\u4e49\u7684\u51fd\u6570\u4f1a\u81ea\u52a8inline\\n  double real() const\\t{return re;} // inline function\\n  double img() const;// declaration\\n  private:\\n  double re,im;\\n}\\n\\n{\\n  complex c1(1,2);  //1+2i\\n  complex c1;  // 0 + 0i\\n  complex *p = new complex(4);\\n}\\n```\\n\\n\u53ef\u4ee5\u628a\u6784\u9020\u51fd\u6570\u653e\u5728private\uff0c\u8868\u793a\u8be5\u7c7b\u5bf9\u8c61\u4e0d\u80fd\u88ab\u5176\u4ed6\u7c7b\u521b\u5efa\uff0c\u4f46\u662f\u53ef\u4ee5\u4f7f\u7528\u53cb\u5143\u6765\u521b\u5efa\u3002\\n\\n\u5e94\u7528\uff1asingleton(\u5355\u4f8b)\u8bbe\u8ba1\u6a21\u5f0f\\n\\n```cpp\\nclass A{\\npublic:\\n  static A& getInstance();\\n  setup(){...};\\nprivate:\\n  A();\\n  A(const A& rhs);\\n  ...\\n}\\n\\nA& A::getInstance(){\\n  static A a;\\n  return a;\\n}\\n\\nA::getInstance().setup();\\n```\\n\\n\\n\\n**Overload(\u91cd\u8f7d)**\\n\\n\u540c\u540d\u51fd\u6570\uff0c\u4e0d\u540c\u53c2\u6570\u5217\u8868\u6216\u8fd4\u56de\u503c\u3002\\n\\n\u80fd\u91cd\u8f7d\u7684\u539f\u56e0\u662f\uff0c\u7f16\u8bd1\u540e\u4e0d\u540c\u53c2\u6570\u8fd4\u56de\u503c\u7684\u540c\u540d\u51fd\u6570\u5728\u7f16\u8bd1\u5668\u770b\u6765\u540d\u5b57\u5e76\u4e0d\u4e00\u6837\\n\\n![image-20230215162624548](assets/image-20230215162624548.png)\\n\\n\\n\\n```cpp\\nclass complex{\\n  public:\\n  // 1\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\\n  // 2\\n  complex():re(0),im(0){}\\n  // 1\u30012\u4e0d\u80fd\u540c\u65f6\u51fa\u73b0\uff0c\u56e0\u4e3a1\u6709\u9ed8\u8ba4\u503c\\n  \\n  // 3\\n  double real() const\\t{return re;} // inline function\\n  double img() const;// declaration\\n  private:\\n  double re,im;\\n}\\n\\n// 4\\nvoid real(double r){real = r;}\\n// 3\u30014\u53ef\u4ee5\u540c\u65f6\u51fa\u73b0\\n```\\n\\n\\n\\n==const member function \uff08\u5e38\u91cf\u6210\u5458\u51fd\u6570\uff09==\\n\\n```cpp\\ndouble real() const{\\n\\treturn re;\\n}\\n```\\n\\n\\n\\n* const\u7528\u5728\u6210\u5458\u51fd\u6570\u8868\u793a\u201c\u4e0d\u4f1a\u6539\u53d8\u7c7b\u5bf9\u8c61\u6570\u636e\u5185\u5bb9\u7684\u6210\u5458\u51fd\u6570\u201d\\n* const int/double/complex \u8868\u793a\u5e38\u91cf\uff0c\u4e0d\u4f1a\u53d1\u751f\u53d8\u5316\u7684\u91cf\\n\\n\u4e0b\u9762\u8fd9\u79cd\u60c5\u51b5\uff0cconst member function\u7684const\u4e0d\u53ef\u7701\u7565\uff0c\u5426\u5219\u7f16\u8bd1\u4e0d\u901a\u8fc7.\\n\\n```cpp\\ndouble real() const{\\n\\treturn re;\\n}\\n\\n{\\n  const complex c(2,1);\\n  cout << c1.real();\\n}\\n```\\n\\n==const \u5bf9\u8c61 \u53ea\u80fd\u8c03\u7528 \u6709const\u7684\u6210\u5458\u53d8\u91cf==\\n\\n* \u7c7b\u4e2d\u67d0\u4e2a\u51fd\u6570\u52a0\u4e86const\uff0c\u8fd9\u65f6\u5019\u5176\u4ed6\u4eba\u5b9a\u4e49\u7684\u65e0\u8bba\u662fconst\u7684\u5bf9\u8c61\u8fd8\u662f\u975econst\u7684\u5bf9\u8c61\uff0c\u90fd\u53ef\u4ee5\u8c03\u7528\u8fd9\u4e2a\u51fd\u6570\\n* \u4f46\u67d0\u4e2a\u51fd\u6570\u6ca1\u6709\u52a0const\uff08\u5373\u6210\u5458\u53d8\u91cf\u53ef\u4ee5\u88ab\u4fee\u6539\uff09\uff0c\u8fd9\u65f6\u5019\u5176\u4ed6\u4eba\u5b9a\u4e49\u4e86\u4e00\u4e2aconst\u7684\u5bf9\u8c61\uff0c\u5c31\u65e0\u6cd5\u518d\u8c03\u7528\u8fd9\u4e2a\u53ef\u4ee5\u4fee\u6539\u6210\u5458\u53d8\u91cf\u7684\u51fd\u6570\u4e86\u3002\\n\\n\u56e0\u6b64\u7c7b\u8bbe\u8ba1\u8005\u8981\u5e94const\u5c3dconst\u3002\\n\\n\\n\\n\\n\\n## \u53c2\u6570\u4f20\u9012/\u8fd4\u56de\u503c\u4f20\u9012\\n\\n* pass by Value\\n* pass by Reference\\n* pass by Reference Const\\n\\n\u5c3d\u91cf\u4e0d\u8981pass by Value\\n\\n\u5f15\u7528\u5728\u5e95\u5c42\u5176\u5b9e\u5c31\u662f\u6307\u9488\\n\\nReference Const\u5c31\u662f\u4f20\u9012\u5f15\u7528\uff0c\u4f46\u662f\u51fd\u6570\u4e0d\u80fd\u5bf9\u8fd9\u4e2a\u5f15\u7528\u8fdb\u884c\u4fee\u6539\uff0c\u5426\u5219\u7f16\u8bd1\u4f1a\u51fa\u9519\\n\\n\\n\\n* return  by Value\\n\\n* return by Reference\\n\\n  \u6bd4\u8f83\u8fd9\u4e24\u79cd\u65b9\u5f0f\\n\\n  \uff081\uff09\\n\\n  ```cpp\\n  inline complex& __doapl(complex *ths, const complex &r){// doapl == do assignment plus\\n    ths->re += r.re;\\n    ths->im += r.im;\\n    return *ths; // ths\u662f\u4e2a\u6307\u9488\uff0c *ths\u662f\u6307\u9488\u6307\u5411\u7684\u5bf9\u8c61\uff0c\u8fd4\u56de\u4e00\u4e2a\u5bf9\u8c61\u7684\u5f15\u7528\\n  }\\n  \\n  // \u6b64\u65f6\uff0c\u522b\u4eba\u8c03\u7528\u8fd9\u4e2a\u51fd\u6570\\n  complex c3;\\n  c3 = __doapl(&c1, c2); // \u7b49\u53f7\u524d\u9762\u7684c3\u4e0d\u7528\u601d\u7d22\u5c31\u80fd\u76f4\u63a5\u5199\u4e86\\n  ```\\n\\n  \uff082\uff09\\n\\n  ```cpp\\n  inline complex __doapl(complex *ths, const complex &r){// doapl == do assignment plus\\n    ths->re += r.re;\\n    ths->im += r.im;\\n    return *ths;\\n  }\\n  complex c3;\\n  c3 = __doapl(&c1, c2);\\n  \\n  \\n  inline complex __doapl(complex *ths, const complex &r){// doapl == do assignment plus\\n    ths->re += r.re;\\n    ths->im += r.im;\\n    return *ths;\\n  }\\n  complex *c3 = new complex();\\n  *c3 = __doapl(&c1, c2);\\n  \\n  // \u8c03\u7528\u8005\u9700\u8981\u601d\u8003\u4e00\u4e0b\u662f\u5199 c3 \u8fd8\u662f *c3\\n  ```\\n\\n  \u8c03\u7528\u8be5\u51fd\u6570\u7684\u4eba\u4e0d\u7528\u77e5\u9053\u4f20\u9012\u7684\u4e1c\u897f\u662f\u4ec0\u4e48\u5f62\u5f0f\u7684\uff08by reference\u6216by value\uff09\\n\\n* return by Reference Const\\n\\n\u5982\u679c\u53ef\u4ee5\u7684\u8bdd\u5c3d\u91cf\u8fd4\u56dereference\uff0c\u4e3a\u4e86\u66f4\u5feb\u3002\\n\\n\u4e0d\u80fd\u8fd4\u56dereference\u7684\u60c5\u51b5\uff1a\u9700\u8981\u8fd4\u56de\u4e00\u4e2a\u65b0\u521b\u5efa\u7684\u5bf9\u8c61\uff0c\u800c\u4e0d\u80fd\u7528\u5df2\u6709\u7684\u4ee3\u66ff\uff0c\u56e0\u4e3a\u5728\u51fd\u6570\u7ed3\u675f\u65f6\uff0c\u65b0\u521b\u5efa\u7684\u5bf9\u8c61\u4e5f\u6ca1\u4e86\uff01\\n\\n## friend\u53cb\u5143\\n\\n\u58f0\u660e\u4e00\u4e2afriend\u51fd\u6570\uff0c\u53ef\u4ee5\u4e0d\u7ecf\u8fc7public\u65b9\u6cd5\uff0c\u76f4\u63a5\u83b7\u5f97\u7c7b\u5bf9\u8c61\u7684private\u6570\u636e\u3002\\n\\n```cpp\\nclass complex{\\n  public:\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\xb7\\n  \\n  double real() const\\t{return re;} // inline function\\n  double img() const;// declaration\\n  private:\\n  double re,im;\\n  \\n  // \u58f0\u660e\u53cb\u5143\\n  friend complex& __doapl(complex*, const complex&);\\n}\\n\\ninline complex& __doapl(complex* ths,const complex& r){\\n  ths->re += r.re;\\n  ths->im += r.im;\\n  return *ths;\\n}\\n\\n\\n```\\n\\n\\n\\n**\u76f8\u540cclass\u7684\u5404\u4e2aObjects\u4e92\u4e3a\u53cb\u5143**\\n\\n```cpp\\nclass complex{\\n  public:\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\\n  \\n int func(const complex& param){\\n   return param.re;\\n }\\n  private:\\n  double re,im;\\n}\\n\\n{\\n  complex c1(2,1);\\n  commplex c2;\\n  c2.func(c1);\\n}\\n```\\n\\n\\n\\n## \u64cd\u4f5c\u7b26\u91cd\u8f7d\u548c\u4e34\u65f6\u5bf9\u8c61\\n\\nc++\u91cc\u64cd\u4f5c\u7b26\u4e5f\u662f\u4e00\u79cd\u51fd\u6570\uff0c\u53ef\u4ee5\u91cd\u65b0\u5b9a\u4e49\u7684\\n\\n### \u7c7b\u5185\u90e8\u7684\u64cd\u4f5c\u7b26\u91cd\u8f7d\\n\\n```cpp\\ninline complex& __doapl(complex *ths, const complex &r){// doapl == do assignment plus\\n  ths->re += r.re;\\n  ths->im += r.im;\\n  return *ths;\\n}\\n\\n// 1\\ninline complex& += (const complex &r){\\n  return __doapl(this, r);\\n}\\n\\n// 2  \u662f\u9519\u7684 this\u4e0d\u80fd\u5199\u51fa\u6765 \u4ed6\u662f\u88ab\u7f16\u8bd1\u5668\u5904\u7406\u4e4b\u540e\u7684\u7ed3\u679c\uff08\u4e0b\u56fe\u662f\u793a\u610f\u56fe\uff09\\n//    \u7f16\u8bd1\u5668\u5904\u7406\u540e\u7684this\u53ef\u80fd\u662f\u7b2c\u4e00\u4e2a\u53c2\u6570\uff0c\u4e5f\u53ef\u80fd\u662f\u6700\u540e\u4e00\u4e2a\u53c2\u6570\uff0c\u53d6\u51b3\u4e8e\u4e0d\u540c\u7684\u7f16\u8bd1\u5668\\ninline complex& += (this, const complex &r){\\n  return __doapl(this, r);\\n}\\n\\n\\n```\\n\\n>  \u7f16\u8bd1\u5668\u770b\u5f85\u201cc2 += c1\u201d\\n>\\n>  += (c2, c1)\\n>\\n>  +=\u662f\u4e00\u4e2a\u51fd\u6570\\n\\n\\n\\n![image-20230215162547923](assets/image-20230215162547923.png)\\n\\n**this**\\n\\n\u6240\u6709\u7684\u6210\u5458\u51fd\u6570\u90fd\u542b\u6709\u4e00\u4e2a\u9690\u85cf\u7684\u53c2\u6570\uff1a this\uff0c \u53ef\u4ee5\u628a\u5b83\u5199\u51fa\u6765\u3002\\n\\n\u8c01\u8c03\u7528\u8fd9\u4e2a\u51fd\u6570\uff0c\u8c01\u5c31\u662f\u90a3\u4e2athis\u3002\\n\\nthis\u662f\u4e2a\u6307\u9488\uff0c\u6307\u5411\u8c03\u7528\u51fd\u6570\u7684\u5bf9\u8c61\\n\\n\\n\\n> \u4e3a\u4ec0\u4e48\u8981\u8bbe\u8ba1\u6210\u6709\u8fd4\u56de\u503c \u800c\u4e0d\u662fvoid\uff1a \u4e3a\u4e86 c1 += c2 += c3\\n>\\n> \u4ece\u540e\u5f80\u524d\uff1a c2 += c3 \u7136\u540e c1 += c2\\n\\n\\n\\n### \u7c7b\u5916\u7684\u64cd\u4f5c\u7b26\u91cd\u8f7d\\n\\n```cpp\\nc2 = c1 + c2\\nc2 = 7 + c1\\n//\u591a\u79cd\u52a0\u6cd5\uff0c\u6240\u4ee5\u4e0d\u80fd\u5728\u7c7b\u91cc\u9762\u91cd\u8f7d\\n```\\n\\n\\n\\n```cpp\\ninline complex operator + (const complex &x, const complex &y){\\n  return complex(x.real()+y.real(), x.img()+y.img());\\n}\\n\\ninline complex operator + (int x, const complex &y){\\n  return complex(x + y.real(), x.img()+y.img());\\n}\\n```\\n\\n==\u7edd\u4e0d\u80fd\u8fd4\u56de\u5f15\u7528\uff0c \u56e0\u4e3a\u51fd\u6570\u4f53\u5185\u521b\u5efa\u7684\u4e34\u65f6\u5bf9\u8c61\u4f1a\u5728\u51fd\u6570\u7ed3\u675f\u540e\u6e05\u7a7a==\\n\\n![image-20230215214734334](assets/image-20230215214734334.png)\\n\\n\\n\\n```cpp\\ncout << c1;\\n// \u8fd9\u91cc\u7684<<\u53ea\u80fd\u5199\u6210\u975e\u6210\u5458\u64cd\u4f5c\u7b26\u91cd\u8f7d\uff0c\u56e0\u4e3acout\u8fd9\u4e2a\u5bf9\u8c61\u6539\u4e0d\u4e86\\n```\\n\\n```cpp\\n#include <iostream>\\n\\nostream&\\noperator << (ostream &os, const complex &x){\\n  return os << real(x) << \\" \\" << img(x);\\n}\\n\\n// \u4e3a\u4e86\u89e3\u51b3\u4e00\u8fde\u4e32\u7684\u60c5\u51b5\uff0c\u6240\u4ee5\u4e0d\u80fd\u8bbe\u7f6e\u6210void\u8fd4\u56de\u503c\\ncout << c1 << c2;\\n// \u8fd9\u4e2a\u662f\u4ece\u5de6\u5f80\u53f3\u7684 cout << c1 \u518d << c2\\n```\\n\\n\u4e0a\u8ff0\u8fd4\u56de\u503c\u53ef\u4ee5\u7528&\uff08\u4e0d\u662f\u4e34\u65f6\u5bf9\u8c61\uff09\uff0c \u4e0d\u80fd\u52a0const\uff08\u4e3a\u4e86\u8fde\u7eed\u8f93\u51fa\uff09\\n\\n### \u4e34\u65f6\u5bf9\u8c61\\n\\n```cpp\\ncomplex(a, b) \\ncomplex()\\nint(7)\\n```\\n\\n\u8fd9\u6837\u7684\u5199\u6cd5\u5c31\u662f\u521b\u5efa\u4e34\u65f6\u5bf9\u8c61\uff0c \u5b83\u7684\u751f\u547d\u5728\u4e0b\u4e00\u884c\u5c31\u7ed3\u675f\u4e86\\n\\n\u9700\u8981\u5728\u672c\u884c\u5c31\u8fdb\u884c\u5176\u4ed6\u64cd\u4f5c\uff0c\u6bd4\u5982\\n\\n```cpp\\nreturn complex()\\nstd::cout << complex()\\nauto a = complex()\\n```\\n\\n## ==\u8bbe\u8ba1\u4e00\u4e2aclass\u5e94\u8be5\u6ce8\u610f\u7684\u4e8b\u60c5==\\n\\n1. \u5584\u7528\u6784\u9020\u51fd\u6570\u7684initilization list\\n2. \u6210\u5458\u51fd\u6570\u52a0\u4e0d\u52a0const\uff0c \u5e94\u52a0\u5c3d\u52a0\uff0c\u5426\u5219\u4f1a\u6709\u526f\u4f5c\u7528\\n3. \u53c2\u6570\u3001\u8fd4\u56de\u503c\u4f20\u9012\u5c3d\u91cfpass by reference\u3001return by reference\uff0c\u8003\u8651\u80fd\u4e0d\u80fd\u7528reference\uff08\u4e34\u65f6\u53d8\u91cf\uff09\\n4. \u6570\u636e\u5c3d\u53ef\u80fd\u653e\u5728private\\n\\n\\n\\n## BigThree\uff1a\u62f7\u8d1d\u6784\u9020\u3001\u62f7\u8d1d\u51fd\u6570\u3001\u6790\u6784\\n\\n```cpp\\n// \u8bbe\u8ba1\u4e00\u4e2astring.h\\n#ifndef __MYSTRING__\\n#define __MYSTRING__\\n\\nclass string{\\n  \\n}\\n#endif\\n\\n// \u80fd\u591f\u5b9e\u73b0\u4e0b\u5217\u64cd\u4f5c\\n\\nstring s1();\\nstring s1(\\"hello\\");\\nstring s3(s1); // \u62f7\u8d1d\u6784\u9020\\n\\ncout << s3 << endl;\\ns3 = s2; // \u62f7\u8d1d\u590d\u5236\\ncout << s3 << endl;\\n```\\n\\n\u5982\u679c\u6ca1\u6709\u5199\u62f7\u8d1d\u6784\u9020\u548c\u62f7\u8d1d\u590d\u5236\uff0c\u7f16\u8bd1\u5668\u4f1a\u81ea\u52a8\u7ed9\u5199\u4e00\u4efd\uff0c\u5b83\u7684\u5b9e\u73b0\u662f\u4e00\u4e2abyte\u4e00\u4e2abyte\u7684\u53bb\u590d\u5236\u3002\\n\\n\u5982\u679c\u4e00\u4e2a\u7c7b\u91cc\u9762\u6709\u4e00\u4e2a\u6307\u9488\uff0c\u5c31\u9700\u8981\u81ea\u5df1\u53bb\u5b9e\u73b0\u62f7\u8d1d\uff0c\u5426\u5219\u7f16\u8bd1\u5668\u9ed8\u8ba4\u7684\u62f7\u8d1d\u4f1a\u628a\u62f7\u8d1d\u8fc7\u53bb\u7684\u6307\u9488\u6307\u5411\u540c\u4e00\u4e2a\u5730\u65b9\uff0c\u800c\u4e0d\u662f\u5f00\u4e00\u4e2a\u65b0\u7a7a\u95f4\u3002\\n\\n\\n\\n```cpp\\n\\nclass String{\\n  String(const char* cstr = 0); // ascii 0 is null\\n  String(const String &str); // \u62f7\u8d1d\u6784\u9020\\n  String& operator = (const String &str); // \u62f7\u8d1d\u51fd\u6570\\n  ~String(); // \u6790\u6784\\n  char* get_c_str() const {return m_data};\\n \\n  private:\\n  \\tchar* m_data; // \u53ef\u4ee5\u52a8\u6001\u589e\u957f\uff0c\u7528\u6307\u9488\\n}\\n```\\n\\n\\n\\n```cpp\\nString::String(const char* cstr = 0){\\n  if(cstr){\\n    m_data = new char[strlen(cstr) + 1];\\n    strcpy(m_data, cstr);\\n  }else{\\n    m_data = new char[1];\\n    *m_data = \'\\\\0\';\\n  }\\n}\\n\\nString::~String(){\\n  delete[] m_data;\\n}\\n\\n{\\n  string s1();\\n\\tstring s2(\\"hello\\");\\n  string *p = new string(\\"hello\\");\\n  delete p;\\n  \\n  // \u524d\u4e24\u4e2a\u751f\u547d\u5468\u671f\u7ed3\u675f\u65f6\uff08\u79bb\u5f00\u4f5c\u7528\u57df\uff09\u4f1a\u81ea\u52a8\u8c03\u7528\u6790\u6784\u51fd\u6570\\n  // \u6700\u540e\u4e00\u4e2a\u5f97\u624b\u52a8delete\\n}\\n\\n```\\n\\n\\n\\n\u6d45\u62f7\u8d1d\uff08\u4e0d\u62f7\u8d1d\u503c\uff09\\n\\n\u6839\u636e\u7f16\u8bd1\u5668\u9ed8\u8ba4\u7684\u62f7\u8d1d\u5b9e\u73b0\u65b9\u5f0f\uff08\u4e00\u4e2abit\u4e00\u4e2abit\u62f7\u8d1d\uff09\uff0c\u8fd9\u79cd\u5199\u6cd5\u4f1a\u9020\u6210\u5185\u5b58\u6cc4\u6f0f\\n\\n\u5f00\u4e86\u4e00\u5757\u5185\u5b58\uff0c\u4f46\u6ca1\u6709\u6307\u9488\u6307\u7740\uff08\u518d\u4e5f\u4e0d\u80fd\u7ba1\u7406\u5230\u8fd9\u5757\u5185\u5b58\u4e86\uff09\\n\\n![image-20230218132144354](assets/image-20230218132144354.png)\\n\\n\\n\\n\u6df1\u62f7\u8d1d\\n\\n```cpp\\nstring::string(const string &str){\\n  m_data = new char[strlen(str.m_data) + 1]; // \u76f8\u540cclass\u7684\u5404\u4e2aObjects\u4e92\u4e3a\u53cb\u5143\\n  strcpy(m_data, str.m_data);\\n}\\n\\nstring s1(\\"hello\\");\\nstring s2(s1);\\n```\\n\\n\\n\\n```cpp\\nstring& string::operator=(const string& str){\\n  // \u5148\u6e05\u7a7a\\n  if(this == &str) return *this;// \u68c0\u6d4b\u81ea\u6211\u8d4b\u503c \u4e0d\u5199\u7684\u8bdd\u5982\u679c\u81ea\u6211\u8d4b\u503c\u4f1a\u51fa\u9519\\n  delete[] m_data; \\n  // \u5f00\u7a7a\u95f4\\n  m_data = new char[strlen(str.m_data) + 1];\\n  // \u8d4b\u503c\\n  strcpy(m_data, str.m_data);\\n  return *this;\\n}\\n```\\n\\n==Array new\u4e00\u5b9a\u8981\u642d\u914dArray Delete==\\n\\n\\n\\n```cpp\\nostream& operator<<(ostream &os, const string &str){\\n  os << str.get_c_str();\\n  return os;\\n}\\n```\\n\\n\\n\\n\\n\\n## \u5806\u3001\u6808\u3001\u5185\u5b58\u7ba1\u7406\\n\\n\u6808\uff1astack\uff0c\u5b58\u5728\u4e8e\u4e00\u4e2a\u4f5c\u7528\u57df\u7684\u4e00\u5757\u5185\u5b58\u7a7a\u95f4\\n\\n\u5806\uff1aheap\uff0c \u64cd\u4f5c\u7cfb\u7edf\u63d0\u4f9b\u7684\u5168\u5c40\u7684\u5185\u5b58\u7a7a\u95f4\\n\\n```cpp\\n{\\n  Complex c1(1,2); // stack  \u79bb\u5f00\u4f5c\u7528\u57df\u65f6\u751f\u547d\u81ea\u52a8\u6d88\u5931\uff08\u8c03\u7528\u6790\u6784\u51fd\u6570\uff09\\n  static Complex c2(1,2); // \u79bb\u5f00\u4f5c\u7528\u57df\u65f6\u751f\u547d\u8fd8\u4f1a\u5b58\u5728\\n  Complex *p = new Complex(3); // heap \u79bb\u5f00\u4f5c\u7528\u57df\u65f6\u9700\u8981\u624b\u52a8\u91ca\u653e\uff0c\u5426\u5219\u4f1a\u4e00\u76f4\u5b58\u5728\\n}\\n```\\n\\n\\n\\n```cpp\\n{\\nComplex *p = new Complex;\\n...\\ndelete p; //\u4e00\u5b9a\u8981delete\u6216\u8005\u4f20\u51fa\u53bb\\n}\\n```\\n\\nnew \u7684\u65f6\u5019\u5185\u90e8\u662f malloc\u3001\u8f6c\u578b\u3001\u6784\u9020\u51fd\u6570\\n\\ndelete\u7684\u65f6\u5019\u5185\u90e8\u662f\u6790\u6784\u51fd\u6570\u548c\u91ca\u653e\u5185\u5b58\\n\\n> \u5bf9\u4e8eString\u6765\u8bf4 \u6790\u6784\u51fd\u6570\u6e05\u7a7adata\u7684\u5185\u5b58\u3001\u7136\u540e\u7f16\u8bd1\u5668\u518d\u5220\u9664String\u7c7b\u5185\u7684char *\u6307\u9488\\n\\nnew\u7684\u65f6\u5019\u4f1a\u5206\u914d\u5f88\u591a\u989d\u5916\u7684\u7a7a\u95f4\uff0c\u6bd4\u59828\u5b57\u8282\u7684complex\uff0c\u5b9e\u9645\u80fd\u5206\u914d64\uff08debug mode\uff09/ 16\uff08release mode\uff09\u5b57\u8282\uff0c\u5305\u62ec\u4e09\u6216\u56db\u4e2a\u90e8\u5206\\n\\n\u4e0a\u4e0bcookie\uff08\u8bb0\u5f55\u5206\u914d\u51fa\u53bb\u7684\u5927\u5c0f\uff09\u3001\u7c7b\u5185\u5bb9\u3001debug\u989d\u5916\u6240\u9700\u90e8\u5206\u3001padding\u3002\\n\\n\\n\\n**\u52a8\u6001\u5206\u914d\u6570\u7ec4**\\n\\n```cpp\\nString *p = new String[3];\\ndelete[] p; // \u8c03\u7528\u4e09\u6b21\u6790\u6784\u51fd\u6570\\n\\nString *p = new String[3];\\ndelete p; // \u8c03\u7528\u4e00\u6b21\u6790\u6784\u51fd\u6570\uff08\u5728string\u8fd9\u79cd\u52a8\u6001\u5206\u914d\u7684class\u7684\u60c5\u51b5\u4e0b\u4f1a\u5f15\u8d77\u5185\u5b58\u6cc4\u6f0f \uff09\\n```\\n\\n\\n\\n## \u8f6c\u6362\u51fd\u6570\\n\\n```cpp\\nclass Fraction{\\n  public: \\n  ...\\n    // non-explicit-one-argument ctor\\n    Fraction(int num, int den = 1):m_numerator(num),m_denominator(den){}\\n  \\n    operator double() const{ // \u8f6c\u6362\u51fd\u6570\u4e00\u822c\u90fd\u4f1a\u52a0const\\n    return (double) const(m_numerator / m_denominator);\\n  }  \\n private:\\n    int m_numerator;\\n    int m_denominator;\\n  }\\n}\\n\\nFraction f(3,5);\\ndouble d = 4 + f;\\n// \u7f16\u8bd1\u5668\u5904\u7406\uff1a\\n// 1. \u627e\u6709\u6ca1\u6709\u5168\u5c40\u7684operator +(int, Fraction)\\n// 2. \u627e\u8f6c\u6362\u51fd\u6570\uff0cf\u80fd\u4e0d\u80fd\u8f6c\u4e3adouble\\n```\\n\\n\\n\\n```cpp\\nclass Fraction{\\n  public: \\n  ...\\n    // non-explicit-one-argument ctor\\n    Fraction(int num, int den = 1):m_numerator(num),m_denominator(den){}\\n  }  \\n private:\\n    int m_numerator;\\n    int m_denominator;\\n  }\\n}\\n\\nFraction d2 = f + 4;\\n// \u7f16\u8bd1\u5668\u5904\u7406\uff1a\\n// non-explicit-one-argument ctor: \u5c064\u8f6c\u5316\u4e3afraction\\n```\\n\\n\\n\\n\u4e24\u79cd\u65b9\u6cd5\u5199\u4e00\u8d77\u53ef\u80fd\u9020\u6210\u7f16\u8bd1\u5668\u77db\u76fe\\n\\n```cpp\\nclass Fraction{\\n  public: \\n  ...\\n    // non-explicit-one-argument ctor\\n    Fraction(int num, int den = 1):m_numerator(num),m_denominator(den){}\\n  \\n    operator double() const{ // \u8f6c\u6362\u51fd\u6570\u4e00\u822c\u90fd\u4f1a\u52a0const\\n    return (double) const(m_numerator / m_denominator);\\n  }  \\n private:\\n    int m_numerator;\\n    int m_denominator;\\n  }\\n}\\n\\nFraction f(3,5);\\nFraction d = 4 + f;\\n// \u628af\u8f6c\u4e3adouble \u8fd8\u662f \u628a4\u8f6c\u4e3afraction\\n```\\n\\n\u89e3\u51b3==> explicit\\n\\n\u8868\u793a\u6784\u9020\u51fd\u6570\u53ea\u6709\u663e\u793a\u7684\u5199\u7684\u65f6\u5019\u624d\u80fd\u505a\uff0c\u800c\u4e0d\u80fd\u9690\u5f0f\u8f6c\u5316\\n\\n```cpp\\nexplicit Fraction(int num, int den = 1):m_numerator(num),m_denominator(den){}\\n```\\n\\n## \u7c7b\u6307\u9488\u7c7b\uff08Pointer-like Class\uff09 shared_ptr\u548citerator\\n\\n```cpp\\ntemplete<class T>\\nclass shared_ptr{\\n  public:\\n  T& operator*() const{return *px} // \u5b9a\u4e49 *A \u53d6\u6307\u9488\u5bf9\u5e94\u5185\u5bb9\u7684\u64cd\u4f5c\\n  \\n  T* operator->() const{return px}; // -> \u64cd\u4f5c\u7b26 \u4f1a\u4f5c\u7528\u5728\u4ed6\u524d\u9762\u7684\u90a3\u4e2a\u53d8\u91cf\u4e0a\uff0c\u8fd4\u56de\u503c\u662fT*\\n  \\n  shared_ptr(T *p):px(p){}\\n  private:\\n  T* px;\\n  long *pn;\\n}\\n\\nstruct Foo{\\n  void method(){...}\\n}\\n\\nsp = shared_ptr<Foo> (new Foo());\\nFoo f(*sp);\\nsp->method();\\n// ==>  \u7bad\u5934\u4f5c\u7528\u5728sp\u4e0a\uff0c\u8f6c\u5316\u4e3a px->method();\\n// ==> \u7bad\u5934\u7b26\u53f7\u7684\u7279\u6b8a\u6027\uff0c \u4f1a\u7ee7\u7eed\u6267\u884c\u4e0b\u53bb\uff0c \u800c\u4e0d\u50cf\u5176\u4ed6\u7b26\u53f7\u6267\u884c\u4e00\u6b21\u5c31\u505c\u6b62\\n```\\n\\n```cpp\\ntemplete<class T>\\nstruct __list_node{\\n  void* prev;\\n  void *next;\\n  T data;\\n}\\n\\ntemplete<class T,class Ref, class ptr>\\nstruct __list_iterator{\\n  typedef __list_node<T>* link_type;\\n  link_type node;\\n  \\n  ref operator*() const{ return (*node).data};\\n  ptr operator->() const {return &(operator*())};\\n}\\n\\n\\nlist<Foo> iter;\\niter->method();\\n// ===> &(*iter)->method\\n\\n\\n```\\n\\n## \u7c7b\u51fd\u6570\u7c7b\uff08function-like class\uff09\\n\\n```cpp\\ntemplete<class T1, class T2>\\nstruct pair{\\n  T1 first;\\n  T2 second;\\n  pair():first(T1()),second(T2()){}\\n  pair(const &t1, const &t2):first(t1),second(t2){}\\n}\\n\\n\\ntemple<class Pair>\\nstruct select1st{\\n  const typename  Pair::first_type& operator()(const Pair &x) const{\\n    {return x.first};\\n  }\\n}\\n```\\n\\n## \u6a21\u7248 template\\n\\n\u53ea\u6709\u8fd9\u4e2a\u4f4d\u7f6e typename\u7b49\u4ef7\u4e8eclass\\n\\n#### \u6a21\u7248 \u7c7b\\n\\n```cpp\\ntemple <class T> // \u6216 temple <typename T>\\nclass complex{\\n  public:\\n  \\tcomplex(T r = 0, T i = 0):re(r), im(i){}\\n}\\ncomplex<int>  c1(2, 1);\\n\\n\\n```\\n\\n#### \u6a21\u7248 \u51fd\u6570\\n\\n```cpp\\ntemplete<class T>\\ninline const T& min(const T &a, const T &b\\t){\\n  return b < a ? b : a;\\n}\\n```\\n\\n\u6a21\u7248\u5728\u7684\u6587\u4ef6\u4f1a\u5148\u7f16\u8bd1\u4e00\u6b21\uff0c\u4e0d\u4f1a\u6709\u4ec0\u4e48\u95ee\u9898\uff1b\\n\\n\u4e4b\u540e\u8fd8\u4f1a\u548c\u5176\u4ed6\u6587\u4ef6\u4e00\u8d77\u518d\u7f16\u8bd1\u4e00\u6b21\uff0c\u5982\u679c\u8be5\u7c7b\u578bT\uff0c\u6ca1\u6709\u91cd\u8f7d < \u8fd8\u662f\u4f1a\u62a5\u9519\u3002\\n\\n#### \u6a21\u7248 \u6210\u5458\\n\\n```cpp\\ntemplete <class T1, class T2>\\n\\nstruct pair{\\n  T1 first;\\n  T2 second;\\n  pair(const &T1 a, const &T2 b):first(a),second(b){};\\n  \\n  templete<class U1, class U2>\\n  pair(const pair<U1,U2> &p) first(p.first),second(p.second){}\\n}\\n\\n\\nclass Derived1: public Base1{\\n  \\n}\\n\\nclass Derived2: public Base2{\\n  \\n}\\n\\npair<Derived1, Derived2> p;\\npair<Base1, Base2> p2(p);\\n```\\n\\n\\n\\n#### \u6a21\u7248\u7279\u5316\\n\\n\u7279\u5316 <--\x3e \u6cdb\u5316\\n\\n**\u5168\u7279\u5316**\\n\\n```cpp\\ntemplete <class key>\\nstruct hash { };\\n\\n// \u7279\u5316\uff0c\u67d0\u4e9b\u6307\u5b9a\u7c7b\u578b\u65f6\u7279\u6b8a\u5904\u7406\\ntemplete <>\\nstruct \\thash<char>{\\n  size_t operator()(char x) const {return x};\\n}\\n\\nstruct \\thash<int>{\\n  size_t operator()(int x) const {return x};\\n}\\n\\nstruct \\thash<long>{\\n  size_t operator()(long\\t x) const {return x};\\n}\\n\\n// \u7279\u5316 specialization\\ncout << hash<long>()(1000);\\n```\\n\\n**\u504f\u7279\u5316**\\n\\n\uff081\uff09\u4e2a\u6570\u4e0a\u7684\u504f\\n\\n```cpp\\ntemplete<typename T, typename Alloc=...>\\nclass vector{\\n  \\n};\\n\\ntemplete<typename T, typename Alloc=...>\\nclass vector<bool, Alloc>{\\n  \\n}\\n```\\n\\n\\n\\n(2) \u8303\u56f4\u4e0a\u7684\u504f\\n\\n```cpp\\ntemplete <typename T>\\nclass C{\\n  \\n}\\n\\ntemplete <typename U>\\nclass C<U*>{\\n  ...\\n}\\n\\n//\\nC<string> c1;\\nC<string*> c2;\\n```\\n\\n\\n\\n\\n\\n#### \u6a21\u7248\u5957\u6a21\u7248\\n\\n```cpp\\ntemplete<typename T, templete <typename T>\\n                     class Container>\\nclass XCLs{\\n  private Container<T> c;\\n}\\n\\nXCLs<string, list> mylst;\\n\\n```\\n\\n\\n\\n## C++\u6807\u51c6\u5e93\\n\\n### Containers\uff08\u5bb9\u5668\uff09\\n\\n1. **Sequence**\uff1aarray\uff0c vector\uff0c deque\uff0c forwar_list\uff0c list\\n2. **container adaptors**: stack, queue, priority_queue\\n3. **associate** : set, multiset, map, multimap\\n4. **unordered associate**: unordered_set, unordered_multiset, unordered_map, unordered_multimap\\n\\n\\n\\n![image-20230308224157732](assets/image-20230308224157732.png)"},{"id":"/RBTree/\u7ea2\u9ed1\u6811","metadata":{"permalink":"/blog/RBTree/\u7ea2\u9ed1\u6811","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/RBTree/\u7ea2\u9ed1\u6811.md","source":"@site/blog/RBTree/\u7ea2\u9ed1\u6811.md","title":"\u7ea2\u9ed1\u6811","description":"\u5b9a\u4e49\u548c\u6027\u8d28","date":"2021-06-10T23:12:01.000Z","formattedDate":"June 10, 2021","tags":[{"label":"Algorithm","permalink":"/blog/tags/algorithm"}],"readingTime":5.61,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"\u7ea2\u9ed1\u6811","date":"2021-06-10T23:12:01.000Z","tags":["Algorithm"]},"prevItem":{"title":"c++\u9762\u5411\u5bf9\u8c61","permalink":"/blog/c++\u9762\u5411\u5bf9\u8c61/\u9762\u5411\u5bf9\u8c61"},"nextItem":{"title":"Djikstra\u9898\u578b\u603b\u7ed3","permalink":"/blog/Dijkstra/Djikstra\u9898\u578b\u603b\u7ed3"}},"content":"\x3c!--truncate--\x3e\\n## \u5b9a\u4e49\u548c\u6027\u8d28\\n\u7ea2\u9ed1\u6811\u662f\u4e00\u79cd\u542b\u6709\u7ea2\u9ed1\u7ed3\u70b9\u5e76\u80fd\u81ea\u5e73\u8861\u7684\u4e8c\u53c9\u67e5\u627e\u6811\u3002\u5b83\u5fc5\u987b\u6ee1\u8db3\u4e0b\u9762\u6027\u8d28\uff1a\\n* \u6027\u8d281\uff1a\u6bcf\u4e2a\u8282\u70b9\u8981\u4e48\u662f\u9ed1\u8272\uff0c\u8981\u4e48\u662f\u7ea2\u8272\u3002\\n* \u6027\u8d282\uff1a\u6839\u8282\u70b9\u662f\u9ed1\u8272\u3002\\n* \u6027\u8d283\uff1a\u6bcf\u4e2a\u53f6\u5b50\u8282\u70b9\uff08NIL\uff09\u662f\u9ed1\u8272\u3002\\n* \u6027\u8d284\uff1a\u6bcf\u4e2a\u7ea2\u8272\u7ed3\u70b9\u7684\u4e24\u4e2a\u5b50\u7ed3\u70b9\u4e00\u5b9a\u90fd\u662f\u9ed1\u8272\u3002\\n* \u6027\u8d285\uff1a\u4efb\u610f\u4e00\u7ed3\u70b9\u5230\u6bcf\u4e2a\u53f6\u5b50\u7ed3\u70b9\u7684\u8def\u5f84\u90fd\u5305\u542b\u6570\u91cf\u76f8\u540c\u7684\u9ed1\u7ed3\u70b9\uff08\u9ed1\u8272\u5b8c\u7f8e\u5e73\u8861\uff09\u3002\u5b9a\u4e49\u4e3a\u9ed1\u9ad8black-height \u8bb0\u4f5cbh(x)\\n\u4e3a\u4fbf\u4e8e\u8fb9\u754c\u5904\u7406\uff0c\u6211\u4eec\u91c7\u7528\u4e00\u4e2a\u548c\u666e\u901a\u8282\u70b9\u62e5\u6709\u76f8\u540c\u6570\u636e\u7ed3\u6784\u7684\u54e8\u5175\u5bf9\u8c61\u6765\u4ee3\u8868\u53f6\u8282\u70b9NIL\uff0c\u53f6\u8282\u70b9\u4e0d\u5b58\u50a8\u4fe1\u606f\uff0c\u53ea\u7528\u6765\u6307\u793a\u8fb9\u754c\u3002\\n\\n\u4f18\u79c0\u7684\u6027\u8d28\uff1a\u4e00\u68f5\u6709n\u4e2a\u5185\u90e8\u8282\u70b9\u7684\u7ea2\u9ed1\u6811\u9ad8\u5ea6\u81f3\u591a\u4e3a2lg(n+1).\u56e0\u6b64\u589e\u5220\u67e5\u6539\u64cd\u4f5c\u590d\u6742\u5ea6\u90fd\u662fO\uff08lg n\uff09\\n\\n\u7ea2\u9ed1\u6811\u81ea\u5e73\u8861\u901a\u8fc7\u4e09\u79cd\u64cd\u4f5c\u5b9e\u73b0\uff1a\\n1. \u5de6\u65cb\uff1a\u4ee5\u67d0\u4e2a\u7ed3\u70b9\u4f5c\u4e3a\u652f\u70b9(\u65cb\u8f6c\u7ed3\u70b9)\uff0c\u5176\u53f3\u5b50\u7ed3\u70b9\u53d8\u4e3a\u65cb\u8f6c\u7ed3\u70b9\u7684\u7236\u7ed3\u70b9\uff0c\u53f3\u5b50\u7ed3\u70b9\u7684\u5de6\u5b50\u7ed3\u70b9\u53d8\u4e3a\u65cb\u8f6c\u7ed3\u70b9\u7684\u53f3\u5b50\u7ed3\u70b9\uff0c\u5de6\u5b50\u7ed3\u70b9\u4fdd\u6301\u4e0d\u53d8\u3002\\n2. \u53f3\u65cb\uff1a\u4ee5\u67d0\u4e2a\u7ed3\u70b9\u4f5c\u4e3a\u652f\u70b9(\u65cb\u8f6c\u7ed3\u70b9)\uff0c\u5176\u5de6\u5b50\u7ed3\u70b9\u53d8\u4e3a\u65cb\u8f6c\u7ed3\u70b9\u7684\u7236\u7ed3\u70b9\uff0c\u5de6\u5b50\u7ed3\u70b9\u7684\u53f3\u5b50\u7ed3\u70b9\u53d8\u4e3a\u65cb\u8f6c\u7ed3\u70b9\u7684\u5de6\u5b50\u7ed3\u70b9\uff0c\u53f3\u5b50\u7ed3\u70b9\u4fdd\u6301\u4e0d\u53d8\u3002\\n3. \u53d8\u8272\uff1a\u7ed3\u70b9\u7684\u989c\u8272\u7531\u7ea2\u53d8\u9ed1\u6216\u7531\u9ed1\u53d8\u7ea2\u3002\\n\u4e0a\u8ff0\u65cb\u8f6c\u64cd\u4f5c\u540cAVL\u3002\\n\\n## \u67e5\u627e\\n\u56e0\u4e3a\u7ea2\u9ed1\u6811\u662f\u4e00\u9897\u4e8c\u53c9\u5e73\u8861\u6811\uff0c\u5e76\u4e14\u67e5\u627e\u4e0d\u4f1a\u7834\u574f\u6811\u7684\u5e73\u8861\uff0c\u6240\u4ee5\u67e5\u627e\u8ddf\u4e8c\u53c9\u5e73\u8861\u6811\u7684\u67e5\u627e\u65e0\u5f02\uff1a\\n\uff081\uff09\u4ece\u6839\u7ed3\u70b9\u5f00\u59cb\u67e5\u627e\uff0c\u628a\u6839\u7ed3\u70b9\u8bbe\u7f6e\u4e3a\u5f53\u524d\u7ed3\u70b9\uff1b\\n\uff082\uff09\u82e5\u5f53\u524d\u7ed3\u70b9\u4e3a\u7a7a\uff0c\u8fd4\u56denull\uff1b\\n\uff083\uff09\u82e5\u5f53\u524d\u7ed3\u70b9\u4e0d\u4e3a\u7a7a\uff0c\u7528\u5f53\u524d\u7ed3\u70b9\u7684key\u8ddf\u67e5\u627ekey\u4f5c\u6bd4\u8f83\uff1b\\n\uff084\uff09\u82e5\u5f53\u524d\u7ed3\u70b9key\u7b49\u4e8e\u67e5\u627ekey\uff0c\u90a3\u4e48\u8be5key\u5c31\u662f\u67e5\u627e\u76ee\u6807\uff0c\u8fd4\u56de\u5f53\u524d\u7ed3\u70b9\uff1b\\n\uff085\uff09\u82e5\u5f53\u524d\u7ed3\u70b9key\u5927\u4e8e\u67e5\u627ekey\uff0c\u628a\u5f53\u524d\u7ed3\u70b9\u7684\u5de6\u5b50\u7ed3\u70b9\u8bbe\u7f6e\u4e3a\u5f53\u524d\u7ed3\u70b9\uff0c\u91cd\u590d\u6b65\u9aa42\uff1b\\n\uff086\uff09\u82e5\u5f53\u524d\u7ed3\u70b9key\u5c0f\u4e8e\u67e5\u627ekey\uff0c\u628a\u5f53\u524d\u7ed3\u70b9\u7684\u53f3\u5b50\u7ed3\u70b9\u8bbe\u7f6e\u4e3a\u5f53\u524d\u7ed3\u70b9\uff0c\u91cd\u590d\u6b65\u9aa42\uff1b\\n\\n## \u63d2\u5165\\n\\n\u63d2\u5165\u64cd\u4f5c\u5305\u62ec\u4e24\u90e8\u5206\u5de5\u4f5c\uff1a\u4e00\u67e5\u627e\u63d2\u5165\u7684\u4f4d\u7f6e\uff1b\u4e8c\u63d2\u5165\u540e\u81ea\u5e73\u8861\u3002\\n\u67e5\u627e\u63d2\u5165\u7684\u7236\u7ed3\u70b9\u5f88\u7b80\u5355\uff0c\u8ddf\u67e5\u627e\u64cd\u4f5c\u533a\u522b\u4e0d\u5927\uff0c\u9700\u8981\u6ce8\u610f\u7684\u662f\u63d2\u5165\u7684\u8282\u70b9\u5e94\u8be5\u8bbe\u7f6e\u6210\u7ea2\u8272\uff0c\u8fd9\u662f\u56e0\u4e3a\u589e\u52a0\u9ed1\u8272\u8282\u70b9\u5fc5\u7136\u4f1a\u5f15\u8d77\u4e0d\u5e73\u8861\uff08\u6027\u8d285\uff09\\n\\n<font color=\'red\'>\u9700\u8981\u6ce8\u610f\u7684\u662f\uff0c\u4e0b\u9762\u6240\u6709\u793a\u610f\u56fe\uff0c\u5706\u5708+\u7f16\u53f7\u8868\u793a\u7684\u8282\u70b9\uff08\u9664\u4e86\u660e\u786e\u6807\u51fa\u5b69\u5b50\u8282\u70b9\u7684\uff09\u8868\u793a\u4ee5\u8be5\u7f16\u53f7\u4e3a\u6839\u8282\u70b9\u7684\u5b50\u6811\u3002</font>\\n\\n### \u4e0d\u4f1a\u5f15\u8d77\u81ea\u5e73\u8861\u7684\u60c5\u51b5\\n1. \u7ea2\u9ed1\u6811\u4e3a\u7a7a\\n\u63d2\u5165\u8282\u70b9\u4f5c\u4e3a\u6839\u8282\u70b9\uff0c\u8bbe\u7f6e\u6210\u9ed1\u8272\uff1b\\n\\n2. \u63d2\u5165\u8282\u70b9key\u5df2\u5b58\u5728\\n\u8fd9\u91cc\u6309\u7167java hashmap\u7684\u5199\u6cd5\uff0c\u9ed8\u8ba4key\u4e0d\u91cd\u590d\uff0c\u56e0\u6b64insert\u9000\u5316\u4e3aupdate\\n\\n3. \u63d2\u5165\u8282\u70b9\u7684\u7236\u8282\u70b9\u4e3a\u9ed1\u8282\u70b9\\n\u63d2\u5165\u8282\u70b9\u662f\u7ea2\u8272\uff0c\u76f4\u63a5\u63d2\u5165\uff0c\u65e0\u9700\u81ea\u5e73\u8861\\n\\n### \u9700\u8981\u81ea\u5e73\u8861\u7684\u60c5\u51b5\\n\u63d2\u5165\u8282\u70b9\u7684\u7236\u8282\u70b9\u4e3a\u7ea2\u8282\u70b9\u53ef\u80fd\u5f15\u8d77\u81ea\u5e73\u8861\u3002\u9996\u5148\uff0c\u56e0\u4e3a\u6839\u8282\u70b9\u4e00\u5b9a\u662f\u9ed1\u8282\u70b9\uff0c\u6240\u4ee5\u63d2\u5165\u8282\u70b9\u7684\u7236\u8282\u70b9\u4e00\u5b9a\u4e0d\u662f\u8ddf\u8282\u70b9\uff0c\u6240\u4ee5\u63d2\u5165\u8282\u70b9\u4e00\u5b9a\u6709\u7956\u7236\u8282\u70b9\u3002\\n\\n#### \u53d4\u53d4\u8282\u70b9\u5b58\u5728\u5e76\u4e14\u4e3a\u7ea2\u8282\u70b9\\n![](\u7ea2\u9ed1\u6811/2.png)\\n\u63d2\u5165\u8282\u70b9\u662f\u7ea2\u8272\uff0c\u56e0\u4e3a\u7ea2\u8282\u70b9\u7684\u4e24\u4e2a\u5b50\u8282\u70b9\u5fc5\u987b\u662f\u9ed1\u8272\uff0c\u6240\u4ee5\u9996\u5148\u5c06\u63d2\u5165\u8282\u70b9\u7684\u7956\u7236\u548c\u7236\u8f88\u7684\u9ed1\u7ea2\u7ea2\u53d8\u4e3a\u7ea2\u9ed1\u9ed1\uff0c\u7531\u4e8e\u7956\u7236\u8282\u70b9\u53d8\u4e3a\u7ea2\uff0c\u5bf9\u4e8e\u4e0a\u5c42\u53ef\u80fd\u4f1a\u4e0d\u6ee1\u8db3\u6027\u8d284\uff0c\u56e0\u6b64\u5c06\u7956\u7236\u8282\u70b9\u4f5c\u4e3a\u65b0\u7684\u63d2\u5165\u8282\u70b9\uff08\u7814\u7a76\u5bf9\u8c61\uff09\u3002\\n\u8003\u8651\u81ea\u4e0b\u800c\u4e0a\u7684\u53d8\u52a8\u5230\u8fbe\u8fb9\u754c\u6761\u4ef6\uff0c\u5373\u5982\u679c\u7956\u7236\u8282\u70b9A\u662f\u6839\u8282\u70b9\u4e86\uff0c\u5fc5\u987b\u91cd\u65b0\u5c06\u6839\u8282\u70b9\u5237\u4e3a\u9ed1\u8272\uff0c\u8fd9\u6837\u4f1a\u4f7f\u6574\u4f53\u9ed1\u9ad8\u589e\u52a01\uff0c\u8fd9\u4e5f\u662f\u552f\u4e00\u4e00\u79cd\u4f1a\u589e\u52a0\u9ed1\u8272\u8282\u70b9\u5c42\u6570\u7684\u60c5\u666f\u3002\\n\\n#### \u53d4\u53d4\u8282\u70b9\u4e0d\u5b58\u5728\u6216\u4e3a\u9ed1\u8282\u70b9\\n\u4ee5\u4e0b\u7c7b\u4f3c\u4e8eAVL\u5206\u5de6\u5de6\u3001\u5de6\u53f3\u3001\u53f3\u5de6\u3001\u53f3\u53f3\u56db\u79cd\u60c5\u51b5\\n##### 1. \u5de6\u5de6\\n![](\u7ea2\u9ed1\u6811/3.png)\\n##### 2. \u5de6\u53f3\\n![](\u7ea2\u9ed1\u6811/4.png)\\n##### 3. \u53f3\u5de6\\n![](\u7ea2\u9ed1\u6811/5.png)\\n##### 4. \u53f3\u53f3\\n![](\u7ea2\u9ed1\u6811/6.png)\\n\\n## \u4ee3\u7801"},{"id":"/Dijkstra/Djikstra\u9898\u578b\u603b\u7ed3","metadata":{"permalink":"/blog/Dijkstra/Djikstra\u9898\u578b\u603b\u7ed3","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/Dijkstra/Djikstra\u9898\u578b\u603b\u7ed3.md","source":"@site/blog/Dijkstra/Djikstra\u9898\u578b\u603b\u7ed3.md","title":"Djikstra\u9898\u578b\u603b\u7ed3","description":"\u6982\u8ff0","date":"2020-06-14T20:20:48.000Z","formattedDate":"June 14, 2020","tags":[{"label":"Algorithm","permalink":"/blog/tags/algorithm"}],"readingTime":3.36,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"Djikstra\u9898\u578b\u603b\u7ed3","date":"2020-06-14T20:20:48.000Z","tags":["Algorithm"]},"prevItem":{"title":"\u7ea2\u9ed1\u6811","permalink":"/blog/RBTree/\u7ea2\u9ed1\u6811"}},"content":"\x3c!--truncate--\x3e\\n## \u6982\u8ff0\\n\u4f7f\u7528Dijkstra\u7684\u6700\u77ed\u8def\u7684\u95ee\u9898\u901a\u5e38\u4e0d\u4ec5\u8981\u6c42\u7ed9\u51fa\u6700\u77ed\u8def\u5f84\uff0c\u8fd8\u9644\u5e26\u4ee5\u4e0b\u51e0\u79cd\u9898\u578b\u6216\u5176\u7ec4\u5408\uff1a\\n- \u989d\u5916\u589e\u52a0\u4e00\u4e2a\u8fb9\u6743\uff0c\u7528\u4e8e\u6700\u77ed\u8def\u5f84\u76f8\u540c\u60c5\u51b5\u4e0b\u7684\u6bd4\u8f83\uff1b\\n- \u989d\u5916\u589e\u52a0\u4e00\u4e2a\u70b9\u6743\uff0c\u7528\u4e8e\u6700\u77ed\u8def\u5f84\u76f8\u540c\u60c5\u51b5\u4e0b\u7684\u6bd4\u8f83\uff1b\\n- \u95ee\u6709\u591a\u5c11\u79cd\u6700\u77ed\u8def\uff1b\\n- \u8f93\u51fa\u6700\u77ed\u8def\u7ecf\u8fc7\u8282\u70b9\u3002\\n\\n## \u4ee3\u7801\\n```c++\\n#include <iostream>\\n#include <vector>\\n\\nusing namespace std;\\n\\nconst int MAXV = 510; //\u6700\u5927\u9876\u70b9\u6570\uff0c\u901a\u5e38\u53d6\u9898\u76ee\u6240\u7ed9\u6761\u4ef6\u7684\u4e0a\u9650+\uff085\uff5e10\uff09\u5373\u53ef\\nconst int INF = 100000000;//\u5b9a\u4e49\u4e00\u4e2a\u5f88\u5927\u7684\u6570\\n\\nvector<int> Adj[MAXV];//\u56fe\u7684\u90bb\u63a5\u8868\uff08\u53ef\u4ee5\u9009\u62e9\u7528vector<Node> Adj[] \u7ed3\u6784\u4f53\u4e2d\u653e\u5165\u8fb9\u6743\u548c\u70b9\u6743\uff09\\n\\nint d[MAXV];//\u7b2c\u4e00\u7ebf\u6743\uff08\u4ece\u8d77\u70b9s\u5230\u9876\u70b9u\u7684\u6700\u77ed\u8def\u7a0b\u4e3ad[u]\uff09\\nint w[MAXV];//\u70b9\u6743\uff08\u4ece\u8d77\u70b9s\u5230\u9876\u70b9u\u80fd\u6536\u96c6\u5230\u7684\u6700\u591a\u7684\u70b9\u6743\u4e3aw[u]\uff09\\nint c[MAXV];//\u7b2c\u4e8c\u7ebf\u6743\uff08\u4ece\u8d77\u70b9s\u5230\u9876\u70b9u\u82b1\u8d39\u7684\u6700\u5c11\u7ebf\u6743\u4e3ac[u]\uff09\\nint num[MAXV];//\u8bb0\u5f55\u76f8\u540c\u8ddd\u79bb\u8def\u5f84\u4e2a\u6570\\nint pre[MAXV];//\u4ece\u8d77\u70b9\u5230v\u7684\u6700\u77ed\u8def\u5f84\u7684v\u7684\u524d\u4e00\u4e2a\u8282\u70b9\u4e3apre[v]\\n\\nint weight[MAXV];//\u5b58\u50a8\u8f93\u5165\u7684\u70b9\u6743\\nint dist[MAXV][MAXV];//\u5b58\u50a8\u8f93\u5165\u7684\u7b2c\u4e00\u7ebf\u6743\\nint cost[MAXV][MAXV];//\u5b58\u50a8\u8f93\u5165\u7684\u7b2c\u4e8c\u7ebf\u6743\\n\\nbool isVisit[MAXV];//\u7528\u6765\u8bb0\u5f55\u662f\u5426\u8bbf\u95ee\u8fc7\\nint M,N;\\n\\nvoid Dijkstra(int s);\\nvoid print_route(int s, int v);\\n\\nint main(){\\n    /*\\n     * \u8f93\u5165\u7684\u683c\u5f0f\\n     * N\uff08\u8282\u70b9\u4e2a\u6570\uff09 M\uff08\u8fb9\u4e2a\u6570\uff09\\n     * w1 w2 ... wN \uff08\u70b9\u6743\uff09\\n     * v1 v2 distance cost (\u4e24\u9876\u70b9\u7f16\u53f7\uff0c\u4ee5\u53ca\u4e24\u8005\u95f4\u7684\u4e24\u79cd\u8fb9\u6743)\\n     */\\n    cin >> M >> N;\\n    for(int i = 0;i < N;i++){\\n        int temp;\\n        cin >> temp;\\n        weight[i] = temp;\\n    }\\n\\n    for(int i = 0; i < M;i++){\\n        int v1,v2,distance,cost_;\\n        cin >> v1 >> v2 >> distance >> cost_;\\n        dist[v1][v2] = distance;\\n        cost[v1][v2] = cost_;\\n    }\\n\\n    /*\\n     * \u521d\u59cb\u5316\u5168\u5c40\u53d8\u91cf\\n     */\\n    fill(d,d+MAXV,INF);//\u521d\u59cbd\u90fd\u4e3a0\\n    fill(w,w+MAXV,0);\\n    fill(c,c+MAXV,0);\\n\\n    fill(num,num+MAXV,0);\\n    num[0] = 1;\\n\\n    Dijkstra(0);\\n\\n}\\n\\nvoid Dijkstra(int s){//s\u4e3a\u8d77\u70b9\\n    d[s] = 0;//\u8d77\u70b9\u5230\u81ea\u5df1\u8ddd\u79bb\u4e3a0\\n    int u = -1;//\u7528\u6765\u8bb0\u5f55\u5f53\u524d\u7684\u9876\u70b9\\n    for(int i = 0; i < N; i++){//\u8ba1\u7b97\u5230\u6bcf\u4e2a\u70b9\u7684\u6700\u77ed\u8def\u5f84\\n        int MIN = INF;\\n        for(int j = 0;j < N;j++){\\n            if(isVisit[j]== false && d[j] < MIN){\\n                u = j;\\n                MIN = d[j];\\n            }\\n        }\\n        isVisit[u] = true;\\n\\n        for(int j=0; j < Adj[u].size();j++){\\n            int v = Adj[u][j];\\n            if(isVisit[v] == false && d[u] + dist[u][v] < d[v]){//\u4f18\u5148\u7ea7\uff1a\u7b2c\u4e00\u7ebf > \u7b2c\u4e8c\u7ebf > \u70b9\\n                d[v] = d[u] + dist[u][v];//\u7b2c\u4e00\u7ebf\u6743\\n                c[v] = c[u] + cost[u][v];//\u7b2c\u4e8c\u7ebf\u6743\\n                w[v] = w[u] + weight[v];//\u70b9\u6743\\n                num[v] = num[u];\\n                pre[v] = u;\\n            }else if(isVisit[v] == false && d[u] + dist[u][v] == d[v]){\\n                num[v] = num[v] + num[u];//\u52a0\u6cd5\u539f\u7406\\n                if(c[v] > c[u] + cost[u][v]){\\n                    c[v] = c[u] + cost[u][v];//\u9009\u62e9\u66f4\u5c0f\u7684\u82b1\u8d39\\n                    pre[v] = u;\\n                }else if(c[v] == c[u] + cost[u][v]){\\n                    if(w[v] < w[u] + weight[v]){\\n                        w[v] = w[u] + weight[v];\\n                        pre[v] = u;\\n                    }\\n                }\\n\\n            }\\n        }\\n        print_route(s, i);\\n        cout << \\"\\\\n\\";\\n    }\\n}\\n\\nvoid print_route(int s, int v){//\u7c7b\u4f3c\u4e8e\u5e76\u67e5\u96c6\u6216DFS\\n    if(v==s){\\n        cout << s;\\n        return;\\n    }\\n    print_route(s,pre[v]);\\n    cout << v;\\n}\\n\\n```"}]}')}}]);